class Solution:
    def smallestSubsequence(self, s: str) -> str:
        n = len(s)
        last = {c: i for i, c in enumerate(s)}
        stack = []
        for i in range(n):
            while stack and stack[-1] > s[i] and last[stack[-1]] > i:
                stack.pop()
            stack.append(s[i])
        return ''.join(stack)
